#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int D; char s[1005];
        scanf("%d",&D);
        scanf("%s",s);
        int ok=0;
        for(int i=0;i<D;i++) if(s[i]=='0' || s[i]=='5'){ ok=1; break; }
        puts(ok?"Yes":"No");
    }
    return 0;
}

