const T = Number(input[idx++]);
let result = [];
for(let t=0; t<T; t++){
  const D = Number(input[idx++]);
  const s = input[idx++];
  let ok = false;
  for(let i=0; i<D; i++){
    const ch = s.charAt(i);
    if(ch === '0' || ch === '5'){ ok = true; break; }
  }
  result.push(ok ? 'Yes' : 'No');
}
